const ONE_SIXTH = 1.0 / 6.0;
const TWO_THIRD = 2.0 / 3.0;

// Define _v function 
function _v(m1, m2, hue) {
    hue = hue % 1.0;
    if (hue < 0) hue += 1.0;
    if (hue < ONE_SIXTH) {
        return m1 + (m2 - m1) * hue * 6.0;
    }
    if (hue < 0.5) {
        return m2;
    }
    if (hue < TWO_THIRD) {
        return m1 + (m2 - m1) * (TWO_THIRD - hue) * 6.0;
    }
    return m1;
}

// Define hls_to_rgb function
function hls_to_rgb(h, l, s) {
    if (s === 0.0) {
        return [l, l, l];
    }
    var m2;
    if (l <= 0.5) {
        m2 = l * (1.0 + s);
    } else {
        m2 = l + s - (l * s);
    }
    var m1 = 2.0 * l - m2;
    var tmp_1 = _v(m1, m2, h + ONE_THIRD);
    var tmp_2 = _v(m1, m2, h);
    var tmp_3 = _v(m1, m2, h - ONE_THIRD);
    return [tmp_1, tmp_2, tmp_3];
}

